import { iris as remotionIris, type IrisProps as RemotionIrisProps } from '@remotion/transitions/iris';
import type { TransitionPresentation } from '@remotion/transitions';
import { irisSchema, type IrisOptions } from './schema';

export { irisSchema, type IrisOptions };

/**
 * An iris transition — a circular reveal that grows from / collapses
 * toward the canvas center, like a camera shutter opening. Classic
 * cinematic effect; the catalog's most "deliberate" cut.
 *
 * **Requires `width` + `height`** — pass them from `useVideoConfig()` in
 * the surrounding scene (Remotion's iris needs explicit dimensions to
 * size the radial clip path).
 *
 * Pair with the recommended Onda timing for the house feel:
 * `linearTiming({ durationInFrames: 18, easing: Easing.bezier(0.16, 1, 0.3, 1) })`
 *
 * Wraps Remotion's `iris()`.
 */
export function iris(
  options: IrisOptions,
): TransitionPresentation<RemotionIrisProps> {
  const opts = irisSchema.parse(options);
  return remotionIris({ width: opts.width, height: opts.height });
}

export default iris;

import { z } from 'zod';

/** Zod schema for {@link iris} options. */
export const irisSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted (`schema.parse({})` works as before). Lets consumers build `z.discriminatedUnion('kind', [...])` directly over onda schemas. */
  kind: z.literal('iris').default('iris'),
  /** Canvas width in px — typically `useVideoConfig().width`. Required by Remotion's iris. */
  width: z.number().int().positive(),
  /** Canvas height in px — typically `useVideoConfig().height`. */
  height: z.number().int().positive(),
});

export type IrisOptions = z.input<typeof irisSchema>;

# iris

A circular reveal that grows from / collapses toward the canvas center, like a camera shutter opening. Classic cinematic effect — the catalog's most "deliberate" cut.

## Options

| Name | Type | Required | Notes |
| --- | --- | --- | --- |
| `width` | `integer > 0` | ✓ | Canvas width in px. Typically `useVideoConfig().width`. |
| `height` | `integer > 0` | ✓ | Canvas height in px. Typically `useVideoConfig().height`. |

## Usage

```tsx
import { Easing, useVideoConfig } from 'remotion';
import { TransitionSeries, linearTiming } from '@remotion/transitions';
import { iris } from './components/onda/transitions/iris/iris';

const MyScene = () => {
  const { width, height } = useVideoConfig();
  return (
    <TransitionSeries>
      <TransitionSeries.Sequence durationInFrames={150}>
        <Scene1 />
      </TransitionSeries.Sequence>
      <TransitionSeries.Transition
        presentation={iris({ width, height })}
        timing={linearTiming({
          durationInFrames: 18,
          easing: Easing.bezier(0.16, 1, 0.3, 1),
        })}
      />
      <TransitionSeries.Sequence durationInFrames={150}>
        <Scene2 />
      </TransitionSeries.Sequence>
    </TransitionSeries>
  );
};
```

## Composition notes

- **Width / height are required.** Remotion's `iris()` needs explicit dimensions to size the radial clip path. Pull them from `useVideoConfig()`.
- **Centered by default.** The current Remotion `iris()` doesn't expose an x/y center (the spec mentioned this as a possible future option but the underlying API doesn't support it today). If off-center iris becomes important, that's a follow-up.
- **Use sparingly.** Like `flip`, iris is loud — reserve for genuine "this beat is the cut" moments.
